const HR_POLICIES_QUESTIONS = [
  { type: "multiple_choice", question: "Under Policy 2.02, the work period for fire protection personnel is a regularly recurring period that begins at what time and day?", choices: ["A 12:01 a.m. Thursday, running 168 consecutive hours", "B 8:00 a.m. Tuesday, running 504 consecutive hours", "C 7:01 a.m. Thursday, running 336 consecutive hours", "D 8:00 a.m. Monday, running 504 consecutive hours"], answer: 1, explanation: "Per Section 3.2 of Policy 2.02, the work period for fire protection personnel commences at 8:00 a.m. Tuesday and runs for 504 consecutive hours (21 consecutive 24-hour periods)." },
  { type: "multiple_choice", question: "Under Policy 2.02, non-exempt fire protection employees are scheduled for how many hours in a 21-day work period?", choices: ["A 159 hours", "B 336 hours", "C 168 hours", "D 504 hours"], answer: 2, explanation: "Per Section 7.1.A of Policy 2.02, non-exempt employees engaged in sworn fire protection are scheduled for 168 hours in a 21-day work period." },
  { type: "multiple_choice", question: "What is the term for the additional half-time pay fire protection employees receive for the 9 hours between 159 and 168 hours in their work period?", choices: ["A Overtime pay", "B Holiday differential", "C Cycle pay", "D Gap pay"], answer: 2, explanation: "Per Section 7.1.A of Policy 2.02, the additional half-time paid to fire protection employees for the 9 hours in excess of 159 during the regularly scheduled 21-day work period is officially called 'cycle pay.'" },
  { type: "multiple_choice", question: "Under Policy 2.02, what is the maximum number of hours of compensatory time a non-exempt fire protection employee may accrue?", choices: ["A 240 hours", "B 320 hours", "C 400 hours", "D 480 hours"], answer: 3, explanation: "Per Section 7.4.A.1 of Policy 2.02, non-exempt employees engaged in fire protection activities may accrue a maximum of 480 hours of compensatory time." },
  { type: "multiple_choice", question: "According to Policy 2.02, when a non-exempt fire protection employee reaches the maximum allowable compensatory time balance, what must happen to additional overtime?", choices: ["A The employee may choose pay or additional comp time", "B The employee must take mandatory comp time off before earning more", "C The employee must be paid time and a half for all additional overtime", "D The employee can no longer work overtime until the balance is reduced"], answer: 2, explanation: "Per Section 7.4.A.1, once the maximum allowable hours of accrued compensatory time are reached, the employee must be paid time and a half for all additional overtime hours worked until the compensatory time balance is reduced." },
  { type: "multiple_choice", question: "Under Policy 2.02, for non-exempt employees other than fire protection, law enforcement, and animal control, which types of leave count as compensable work time toward overtime?", choices: ["A Annual leave, sick leave, and comp time all count", "B Only hours actually worked and city-observed holidays", "C All paid leave including military and injury leave", "D Hours actually worked and all approved paid leave"], answer: 1, explanation: "Per Section 5.1 of Policy 2.02, for general non-exempt employees, compensable work time includes all hours actually worked and all hours off for a city-observed holiday. Most paid leave such as annual, sick, and military leave does NOT count." },
  { type: "multiple_choice", question: "According to Policy 2.02, for non-exempt fire protection employees, which of the following is counted as compensable work time for overtime purposes?", choices: ["A Only hours actually worked", "B Hours actually worked plus only city-observed holidays", "C All hours actually worked and all hours the employee takes paid leave during regularly scheduled hours", "D Hours actually worked plus annual leave only"], answer: 2, explanation: "Per Section 5.3 of Policy 2.02, for non-exempt fire protection employees, compensable work time includes all hours actually worked and all hours the employee takes paid leave during regularly scheduled work hours, including annual leave, sick leave, comp leave, flexible holidays, etc." },
  { type: "multiple_choice", question: "Under Policy 2.02, standby duty time is treated how for overtime calculation purposes?", choices: ["A It counts as compensable work time at the same rate as regular duty", "B It counts at half the regular rate toward the overtime threshold", "C It is not considered compensable work time for calculating overtime", "D It counts as compensable only if the employee is actually called in"], answer: 2, explanation: "Per Section 5.5 of Policy 2.02, standby duty time shall not be considered compensable work time in calculating overtime for non-exempt employees." },
  { type: "multiple_choice", question: "Policy 2.02 establishes a callback minimum: if a non-exempt employee is called back to the work site at least one hour after their regular shift ended, what is the minimum compensable time they receive?", choices: ["A 1 hour or actual time worked, whichever is greater", "B 2 hours or actual time worked, whichever is greater", "C 4 hours, regardless of actual time worked", "D Actual time worked only, with no minimum"], answer: 1, explanation: "Per Section 5.6 of Policy 2.02, non-exempt employees required to return to the work site at least one hour after the conclusion of their regular shift shall receive a minimum of two (2) hours compensable working time or the actual time at the work site, whichever is greater." },
  { type: "multiple_choice", question: "Under Policy 2.02, a non-exempt employee works 10 minutes of additional time beyond their scheduled shift. How much compensable time are they credited?", choices: ["A 0 minutes (de minimis)", "B 10 minutes exactly", "C 15 minutes", "D 30 minutes"], answer: 2, explanation: "Per Section 7.3.A of Policy 2.02, an employee who works 8 to 22 minutes of additional time shall be credited with 15 minutes of compensable work time." },
  { type: "multiple_choice", question: "According to Policy 2.02, what is the minimum additional work time that is considered 'de minimis' and NOT credited as compensable time?", choices: ["A Less than 5 minutes", "B Less than 8 minutes", "C Less than 10 minutes", "D Less than 15 minutes"], answer: 1, explanation: "Per Sections 7.2 and 7.3 of Policy 2.02, non-exempt employees who work occasional additional time of less than eight (8) minutes shall not be credited with additional compensable work time." },
  { type: "multiple_choice", question: "Under Policy 2.02, if a non-exempt employee works 40 minutes of additional time, how much compensable time are they credited?", choices: ["A 30 minutes", "B 40 minutes", "C 45 minutes", "D 60 minutes"], answer: 2, explanation: "Per Section 7.3.C of Policy 2.02, an employee who works 38 to 52 minutes of additional time shall be credited with 45 minutes of compensable work time." },
  { type: "multiple_choice", question: "Policy 2.02 explicitly prohibits which of the following scheduling practices?", choices: ["A Requiring overtime for operational necessity", "B The early relief of previous shift personnel prior to the next scheduled shift starting time", "C Authorizing compensatory leave in lieu of overtime pay", "D Requiring written approval for all overtime assignments"], answer: 1, explanation: "Per Section 6.2.C of Policy 2.02, the early relief of previous shift personnel prior to the next scheduled shift starting time shall be prohibited." },
  { type: "multiple_choice", question: "According to Policy 2.02, an employee is prohibited from 'volunteering' to perform the same type of work they are paid to do. Who determines whether two types of work are the same?", choices: ["A The Department Director", "B The Fire Chief", "C The Director of Human Resources, or designee", "D The City Manager"], answer: 2, explanation: "Per Section 6.4.B of Policy 2.02, the determination of whether the two types of work are the same shall be made by the Director of Human Resources, or designee." },
  { type: "multiple_choice", question: "Under Policy 2.02, when a supervisor learns an employee wishes to volunteer services to any City department, what must the supervisor do?", choices: ["A Verbally advise the employee that it may be prohibited", "B Approve or deny the request based on the supervisor's own judgment", "C Immediately send a written request to the Director of Human Resources for a determination", "D Contact the City Attorney's office for guidance"], answer: 2, explanation: "Per Section 6.4.D of Policy 2.02, supervisors receiving notification that an employee wishes to volunteer services to any City department or agency shall immediately send a written request to the Director of Human Resources, or designee, for a determination whether the types of work are the same." },
  { type: "multiple_choice", question: "Under Policy 2.02, for non-exempt law enforcement personnel, overtime begins after how many hours in a 14-day work period?", choices: ["A 40 hours", "B 80 hours", "C 168 hours", "D 159 hours"], answer: 1, explanation: "Per Section 7.1.B.3 of Policy 2.02, non-exempt employees engaged in law enforcement activities shall be paid one and one-half their regular hourly rate for all compensable work time in excess of 80 hours in a fourteen (14) day work period." },
  { type: "multiple_choice", question: "According to Policy 2.02, if an employee disputes the calculation of an overtime payment, what must they complete to formally report the discrepancy?", choices: ["A A formal grievance under Policy 4.04", "B A written memo to the Department Director", "C A Payroll Adjustment Request form", "D An email to the Director of Human Resources"], answer: 2, explanation: "Per Section 7.5 of Policy 2.02, an employee who believes overtime calculations are inaccurate must report to their supervisor and complete the Payroll Adjustment Request form." },
  { type: "multiple_choice", question: "Under Policy 2.02, accrued compensatory time paid out upon an employee's separation from employment is calculated at which rate?", choices: ["A The employee's regular rate of pay at the time of hire", "B The average regular rate for the final 5 years of employment", "C Either the final regular rate or the average regular rate for the final 3 years, whichever is higher", "D A flat rate set annually by the City Manager"], answer: 2, explanation: "Per Section 7.4.C.3 of Policy 2.02, payment for accrued compensatory time upon separation shall be calculated at either the final regular rate of pay at termination or the average regular rate for the final three (3) years of employment, whichever is higher." },
  { type: "multiple_choice", question: "Under Policy 2.02, non-exempt EMS employees scheduled in a rotational pattern alternating between 36 and 48 hour workweeks are paid at one and one-half for compensable hours worked between 36 and 40 hours. This timeframe is eligible for which form of compensation?", choices: ["A Pay or compensatory leave at the department's discretion", "B Pay only; it is not eligible for compensatory leave", "C Compensatory leave only", "D Straight-time pay only"], answer: 1, explanation: "Per Section 7.1.C of Policy 2.02, EMS employees working more than 36 hours in a 36-hour week shall be paid one and one-half for compensable hours from 36-40 hours, and this timeframe is not eligible for compensatory leave." },
  { type: "multiple_choice", question: "Under Policy 2.02, nursing mothers are allowed how many breaks of up to 15 minutes to express milk, and how long does this entitlement last?", choices: ["A One 30-minute break; until the child is 6 months old", "B Two 15-minute breaks; until the child is 1 year old", "C Three 15-minute breaks; until the child is 6 months old", "D Two 30-minute breaks; until the child is 2 years old"], answer: 1, explanation: "Per Section 5.9 of Policy 2.02, employees who are nursing mothers shall be allowed two breaks up to 15 minutes in duration to allow the employee to express milk until the employee's child turns one year of age." },
  { type: "multiple_choice", question: "Under Policy 2.02, leave without pay, unpaid absences, and suspensions have what effect on overtime computation?", choices: ["A They are treated the same as paid leave for fire protection employees", "B They are not included in the computation of overtime for any employee", "C They count toward the overtime threshold only for law enforcement employees", "D They count at half the normal rate toward the overtime threshold"], answer: 1, explanation: "Per Section 5.7 of Policy 2.02, leave without pay, other unpaid leave types, absence without leave periods, and suspensions shall not be included in the computation of overtime for any employee." },
  { type: "multiple_choice", question: "Policy 2.02 states that overtime assignments are permitted only when required by what condition?", choices: ["A A direct order from the Department Director", "B A shortfall in minimum staffing levels", "C Operational necessity, without which the normal functioning of the agency would be adversely affected", "D Any situation where a supervisor determines it is needed"], answer: 2, explanation: "Per Section 6.2.A of Policy 2.02, overtime assignments are permitted only when required by operational necessity and without which the normal functioning of the agency concerned would be adversely affected." },
  { type: "multiple_choice", question: "Under Policy 2.02, under what limited circumstance is an employee permitted to perform secondary employment with the City through a temporary services agency?", choices: ["A Never; employees may only hold one City position", "B If they are performing different or dissimilar work from their full-time City position", "C If the Department Director provides written approval", "D If the secondary assignment is in a different City department"], answer: 1, explanation: "Per Section 6.3.C of Policy 2.02, employees may perform secondary employment with the City through a temporary services agency as long as they are not performing the same or similar work as in their full-time City position." },
  { type: "multiple_choice", question: "Policy 2.02 meal period rules state that meal breaks for non-exempt fire protection employees working their regular shift are treated how?", choices: ["A As non-compensable time, not counted toward overtime", "B As compensable time included in the calculation of compensable work time", "C As compensable only when the employee is called to respond to an incident during the meal", "D As compensable only on holidays"], answer: 1, explanation: "Per Section 5.4 and Section 7.1.A of Policy 2.02, meal periods for fire protection employees are paid and included in the calculation of compensable work time." },
  { type: "multiple_choice", question: "Under Policy 2.02, which official is specifically responsible for ensuring that the calculation of overtime for fire protection employees is based on a single 21-day work period?", choices: ["A The Director of Human Resources", "B The City Manager", "C The Fire Chief", "D The Battalion Commander"], answer: 2, explanation: "Per Section 6.1.D of Policy 2.02, the Fire Chief shall ensure that the calculation of overtime is determined based upon compensable work time in a single twenty-one (21) day work period for all eligible employees engaged in fire protection activities." },
  { type: "multiple_choice", question: "Under Policy 2.03 (Standby Duty), what is the ONLY way standby duty is officially established?", choices: ["A Issuance of a City pager to the employee", "B A verbal order from a Battalion Chief or higher", "C A written directive from the department director or designee", "D Being placed on the station's on-call calendar"], answer: 2, explanation: "Per Sections 4.1 and 4.4 of Policy 2.03, standby duty is only officially established via a written directive from the department director or designee. A City-issued pager alone does not constitute an official assignment." },
  { type: "multiple_choice", question: "Under Policy 2.03, personnel assigned to standby duty must be able to report to the designated location within what timeframe of notification?", choices: ["A 30 minutes", "B 45 minutes", "C 1 hour", "D 2 hours"], answer: 2, explanation: "Per Section 4.2.A of Policy 2.03, personnel on standby must be able to personally report to the emergency or designated location within one (1) hour of the original notification." },
  { type: "multiple_choice", question: "Under Policy 2.03, which level of employee is NOT eligible to receive compensation for standby duty status?", choices: ["A Non-exempt employees below the rank of Sergeant", "B Probationary employees", "C Division Manager level and above", "D Part-time employees"], answer: 2, explanation: "Per Section 3.0 of Policy 2.03, eligibility for compensation ends at the Division Manager level. Only employees below this rank receive pay for standby status." },
  { type: "multiple_choice", question: "According to Policy 2.03, how is a nonexempt employee compensated for being on authorized standby duty?", choices: ["A Straight time for all hours on standby", "B One hour of straight-time pay or compensatory time for every eight hours of authorized standby", "C One and one-half hours for every eight hours on standby", "D No compensation for standby status; only actual time worked is compensated"], answer: 1, explanation: "Per Section 5.1.A of Policy 2.03, nonexempt employees earn one (1) hour of straight-time pay or compensatory time for every eight (8) hours of authorized standby." },
  { type: "multiple_choice", question: "Under Policy 2.03, if a nonexempt employee on standby is actually called into work, at what rate are they paid for the actual time worked?", choices: ["A Straight time (1x their regular hourly rate)", "B One and one-quarter times (1.25x) their regular hourly rate", "C One and one-half times (1.5x) their regular hourly rate", "D Double time (2x) their regular hourly rate"], answer: 2, explanation: "Per Section 5.1.C of Policy 2.03, if called to work, nonexempt employees are paid at 1.5 times their regular hourly rate for the actual time worked." },
  { type: "multiple_choice", question: "Under Policy 2.03, travel time compensation for a standby callback ends no later than how long after the work is completed?", choices: ["A Immediately upon leaving the work site", "B 15 minutes after work is completed", "C 30 minutes after work is completed", "D 1 hour after work is completed"], answer: 2, explanation: "Per Section 5.4.A of Policy 2.03, compensation for travel begins at notification and ends no later than thirty (30) minutes after the work is completed." },
  { type: "multiple_choice", question: "Under Policy 2.03, an exempt employee is on authorized standby duty. How much compensation do they receive for the standby status itself?", choices: ["A One hour of pay for every eight hours of standby at their regular rate", "B Half their regular hourly rate for the standby period", "C No compensation or compensatory time for the standby duty status itself", "D The same as nonexempt employees: 1 hour per 8 hours on standby"], answer: 2, explanation: "Per Section 5.2.A of Policy 2.03, exempt employees receive no compensation or compensatory time for the standby duty status itself." },
  { type: "multiple_choice", question: "Under Policy 2.03, if work during standby can be performed via computer or phone from home, how is travel time handled?", choices: ["A Travel time is compensated at the standard rate", "B Travel time is compensated at half the standard rate", "C Travel time is not permitted or compensated", "D Travel time is added to the compensable work time at the same rate as the work itself"], answer: 2, explanation: "Per Section 5.4.B of Policy 2.03, if the work can be completed from home via computer or phone, the member is paid for the work time, but travel time is not permitted or compensated." },
  { type: "multiple_choice", question: "Under Policy 3.01, what is the maximum annual leave carryover balance for a firefighter assigned to a 56-hour workweek?", choices: ["A 400 hours", "B 480 hours", "C 520 hours", "D 560 hours"], answer: 3, explanation: "Per Section 4.3.B.2 of Policy 3.01, the maximum carryover for employees on a 56-hour workweek is 560 hours." },
  { type: "multiple_choice", question: "Under Policy 3.01, how much annual leave does a firefighter with 12 years of service on a 56-hour workweek accrue per pay period?", choices: ["A 5.6 hours", "B 7.0 hours", "C 8.4 hours", "D 9.8 hours"], answer: 2, explanation: "Per Section 4.2.A.2 of Policy 3.01, firefighters with 10 to less than 15 years of service on a 56-hour workweek accrue 8.4 hours per pay period." },
  { type: "multiple_choice", question: "Under Policy 3.01, if a firefighter is in a non-pay status for exactly 14 consecutive calendar days during a pay period, what annual leave accrual do they receive?", choices: ["A A full accrual for the pay period", "B A prorated accrual based on the days worked", "C Zero accrual for that pay period", "D The same accrual, but it is credited on the next pay period"], answer: 2, explanation: "Per Section 4.1.A of Policy 3.01, an employee must be in a non-pay status for less than fourteen (14) consecutive calendar days to receive an accrual. Being in non-pay status for 14 days meets or exceeds that threshold and results in zero accrual." },
  { type: "multiple_choice", question: "Under Policy 3.01, when a month contains three pay periods, what happens to annual leave accrual for the third pay period?", choices: ["A A full accrual is credited", "B A half accrual is credited", "C No accrual is credited for the third pay period", "D The third pay period's accrual is deferred to the following month"], answer: 2, explanation: "Per Section 4.1 of Policy 3.01, no annual leave accrual is awarded for the third pay period in months that contain three pay periods." },
  { type: "multiple_choice", question: "Under Policy 3.01, when a part-time employee who accrues personal leave is promoted to a full-time hazardous duty position, what happens to their personal leave balance?", choices: ["A The entire balance is converted to annual leave", "B The entire balance is paid out and forfeited upon conversion", "C The balance is split 50/50: half to annual leave and half to sick leave", "D The balance is frozen and remains as personal leave"], answer: 2, explanation: "Per Section 4.5.B.1.a of Policy 3.01, when a part-time employee who accrues personal leave converts to a full-time hazardous duty position, the personal leave balance is split 50/50, with half going to annual leave and the other half going to sick leave." },
  { type: "multiple_choice", question: "Under Policy 3.01, in what specific increments may a firefighter on a 56-hour schedule take annual leave?", choices: ["A In any increment of 0.25 hours or more", "B In 1.0 hour increments only", "C In increments of 0.8 or 0.6 hours, and only when combined with Birthday Leave or a Personal Flexible Holiday", "D In 8-hour (full shift) increments only"], answer: 2, explanation: "Per Section 4.4.A.2 of Policy 3.01, firefighters on a 56-hour schedule are only permitted to take annual leave in increments of 0.8 or 0.6 hours, and only when combining it with Birthday Leave or a Personal Flexible Holiday." },
  { type: "multiple_choice", question: "Under Policy 3.01, what happens to accumulated personal leave upon separation from City employment for a part-time employee?", choices: ["A It is paid out at the employee's regular hourly rate", "B It is paid out at a flat rate set by the City Manager", "C There is no monetary payout; accumulated personal leave is forfeited", "D It is converted to sick leave at separation"], answer: 2, explanation: "Per Section 4.6.B of Policy 3.01, there is no monetary payout for accumulated personal leave upon separation from employment for part-time employees." },
  { type: "multiple_choice", question: "Under Policy 3.01, which group of employees is covered by the Annual Leave program (not Personal Leave)?", choices: ["A All part-time employees hired on or after July 1, 1996", "B All full-time employees hired after January 1, 2014, regardless of VRS status", "C All full-time hazardous duty employees (firefighters, sworn police, EMTs)", "D All employees in the VRS Hybrid Retirement Plan"], answer: 2, explanation: "Per Section 3.1.A of Policy 3.01, all full-time hazardous duty employees (firefighters, sworn police, EMTs) in both non-supervisory and supervisory roles are covered under the Annual Leave program." },
  { type: "multiple_choice", question: "Under Policy 3.03 (FMLA), an employee must have worked at least how many hours during the 12 months preceding the leave to be eligible?", choices: ["A 1,000 hours", "B 1,250 hours", "C 1,500 hours", "D 2,080 hours"], answer: 1, explanation: "Per Section 4.3 of Policy 3.03, an employee must have worked at least 1,250 hours during the 12 months immediately preceding the start of the leave to be eligible for FMLA." },
  { type: "multiple_choice", question: "Under Policy 3.03, which type of leave is the ONLY exception that counts as 'hours worked' toward the 1,250-hour FMLA eligibility requirement?", choices: ["A Annual leave (paid)", "B Sick leave (paid)", "C Military leave (paid or unpaid)", "D Compensatory time taken"], answer: 2, explanation: "Per Section 4.3.A of Policy 3.03, paid leave does not count as hours worked. However, military leave (paid or unpaid) shall be calculated as hours worked per USERRA guidelines." },
  { type: "multiple_choice", question: "Under Policy 3.03, the City uses which method to define the standard 12-month FMLA measurement period?", choices: ["A A rolling 12-month period measured backward from the date leave begins", "B The City's fiscal year (July 1 through June 30)", "C The calendar year (January 1 through December 31)", "D The employee's anniversary date of hire"], answer: 2, explanation: "Per Section 6.3.A of Policy 3.03, the twelve (12) month FMLA measurement period shall be the calendar year (January 1 through December 31)." },
  { type: "multiple_choice", question: "Under Policy 3.03, Military Caregiver Leave allows for how many workweeks of leave, and over what period is it calculated?", choices: ["A 12 workweeks in a calendar year", "B 16 workweeks in a rolling 12-month period", "C 24 workweeks in a calendar year", "D 26 workweeks in a single 12-month period beginning the first day leave is taken"], answer: 3, explanation: "Per Section 2.12 of Policy 3.03, Military Caregiver Leave allows up to twenty-six (26) workweeks of leave in a single 12-month period, which begins on the first day the leave is taken." },
  { type: "multiple_choice", question: "Under Policy 3.03, within how many business days must HR/Employee Relations provide the Notice of Eligibility and Rights and Responsibility after learning of a potential FMLA-qualifying reason?", choices: ["A 2 business days", "B 3 business days", "C 5 business days", "D 10 business days"], answer: 2, explanation: "Per Section 6.10.A of Policy 3.03, absent extenuating circumstances, HR/ER shall provide the Notice of Eligibility and Rights and Responsibility within five (5) business days of the initial request." },
  { type: "multiple_choice", question: "Under Policy 3.03, after receiving the Notice of Eligibility from HR, how many days does an employee have to submit the required medical certification?", choices: ["A 10 consecutive calendar days", "B 15 consecutive calendar days", "C 21 consecutive calendar days", "D 30 consecutive calendar days"], answer: 1, explanation: "Per Section 9.1.A of Policy 3.03, the employee shall have fifteen (15) consecutive calendar days from the date of the Notice of Eligibility to submit the required medical certification." },
  { type: "multiple_choice", question: "Under Policy 3.03, if a medical certification is found to be incomplete or vague, how many calendar days does the employee have to 'cure' the deficiency?", choices: ["A 3 calendar days", "B 5 calendar days", "C 7 calendar days", "D 15 calendar days"], answer: 2, explanation: "Per Section 6.11.B of Policy 3.03, the employee shall be provided at least seven (7) calendar days to submit the completed information to cure a deficiency after receiving the written notice of deficiency." },
  { type: "multiple_choice", question: "Under Policy 3.03, which department or entity is specifically designated as the only authorized entity to determine medical eligibility for FMLA and to maintain confidential medical records?", choices: ["A Human Resources / Employee Relations (HR/ER)", "B The employee's immediate supervisor", "C Occupational Safety and Health Services (OSHS)", "D The City Attorney's Office"], answer: 2, explanation: "Per Section 6.6 of Policy 3.03, OSHS shall determine whether or not the employee meets medical eligibility for FML, and per Section 6.7, OSHS is the sole entity authorized to maintain confidential medical records." },
  { type: "multiple_choice", question: "Under Policy 3.03, if an employee fails to specify which type of paid leave to use during FMLA, what leave type is used FIRST in the default order?", choices: ["A Sick leave", "B Annual/PTO leave", "C Maternity/Parental Bonding leave", "D Compensatory time"], answer: 2, explanation: "Per Section 7.1 of Policy 3.03, if an employee fails to communicate their choice of leave, the default order of use is: Maternity/Parental Bonding, then Sick, then Annual/PTO, then Personal, then Compensatory, then Flexible Holiday." },
  { type: "multiple_choice", question: "Under Policy 3.03, an employee on unpaid FMLA leave will stop accruing annual and sick leave after being in a non-paid status for more than how many consecutive calendar days?", choices: ["A 7 consecutive calendar days", "B 14 consecutive calendar days", "C 30 consecutive calendar days", "D 12 weeks"], answer: 1, explanation: "Per Section 11.9 of Policy 3.03, no employee will accrue leave while on unpaid FML for more than fourteen (14) consecutive calendar days." },
  { type: "multiple_choice", question: "Under Policy 3.03, if an employee fails to return to work after FMLA is exhausted, they may be required to repay what?", choices: ["A Their full salary paid during the leave period", "B The City's portion of health insurance premiums paid during unpaid FMLA", "C Administrative costs of processing the leave request", "D Nothing; FMLA protections prevent any repayment obligations"], answer: 1, explanation: "Per Section 11.5 of Policy 3.03, an employee who fails to return to work after FMLA is exhausted shall repay the City's portion of any health insurance premiums paid during the unpaid FMLA period." },
  { type: "multiple_choice", question: "Under Policy 3.03, for 'qualifying exigency' leave, 'short-notice deployment' is defined as notification given how many calendar days or less prior to the date of deployment?", choices: ["A 3 or less calendar days", "B 5 or less calendar days", "C 7 or less calendar days", "D 14 or less calendar days"], answer: 2, explanation: "Per Section 10.2.A of Policy 3.03, short-notice deployment is defined as seven (7) or less calendar days prior to the date of deployment." },
  { type: "multiple_choice", question: "Under Policy 3.03, 'Rest and Recuperation' qualifying exigency leave is limited to how many calendar days per instance?", choices: ["A 5 calendar days", "B 10 calendar days", "C 15 calendar days", "D 30 calendar days"], answer: 2, explanation: "Per Section 10.2.F of Policy 3.03, Rest and Recuperation leave is limited to up to fifteen (15) calendar days for each instance." },
  { type: "multiple_choice", question: "Under Policy 3.03, if an employee has been in a non-paid status for more than 14 consecutive calendar days immediately before a holiday, what happens to their holiday pay?", choices: ["A They receive full holiday pay regardless of non-paid status", "B They are ineligible for holiday compensation for that specific holiday", "C They receive half of their normal holiday pay", "D They may use a flexible personal holiday to replace the holiday pay"], answer: 1, explanation: "Per Section 11.7 of Policy 3.03, employees in a nonpaid status on FML for more than fourteen (14) consecutive calendar days preceding a holiday shall not be eligible for holiday compensation for that holiday." },
  { type: "multiple_choice", question: "Under Policy 3.03, when an employee is required to work mandatory overtime but cannot do so because of FMLA, how are those missed overtime hours treated?", choices: ["A They do not count toward the FMLA 12-week entitlement", "B They count toward the 12-week FMLA entitlement", "C The employee must make up the hours at a later date", "D The employee is paid for those overtime hours"], answer: 1, explanation: "Per Section 6.2.C.2.a of Policy 3.03, if an employee is required to work overtime but cannot because of FMLA, those missed mandatory overtime hours count toward the 12-week entitlement." },
  { type: "multiple_choice", question: "Under Policy 3.03, sick leave may NOT be used for which type of FMLA event?", choices: ["A Leave for the employee's own serious health condition", "B Leave to care for a spouse with a serious health condition", "C Military qualifying exigency leave", "D Leave for the birth and bonding with a newborn"], answer: 2, explanation: "Per Section 7.4 of Policy 3.03, sick leave may not be used for Military Qualifying Exigency leave. This is a specific restriction that does not apply to other FMLA event types." },
  { type: "multiple_choice", question: "Under Policy 3.03, a 'serious health condition' involving 'continuing treatment' generally requires a period of incapacity of more than how many consecutive full calendar days?", choices: ["A More than 2 consecutive full calendar days", "B More than 3 consecutive full calendar days", "C More than 5 consecutive full calendar days", "D More than 7 consecutive full calendar days"], answer: 1, explanation: "Per Section 2.20.B of Policy 3.03, a serious health condition involving continuing treatment requires a period of incapacity of more than three (3) consecutive full calendar days." },
  { type: "multiple_choice", question: "Under Policy 3.03, an employee is considered to have 'returned to work' after FMLA only after they have been back on the job for at least how long?", choices: ["A 7 calendar days", "B 14 calendar days", "C 30 calendar days", "D 90 calendar days"], answer: 2, explanation: "Per Section 11.5 of Policy 3.03, an employee who returns to work for at least thirty (30) calendar days is considered to have returned to work." },
  { type: "multiple_choice", question: "Under Policy 3.04 (Bereavement Leave), how many hours of bereavement leave are granted to a firefighter assigned to a 56-hour workweek?", choices: ["A 40 hours", "B 48 hours", "C 56 hours", "D 64 hours"], answer: 2, explanation: "Per Policy 3.04, personnel assigned to a 56-hour workweek are granted exactly 56 hours of bereavement leave." },
  { type: "multiple_choice", question: "Under Policy 3.04, which of the following family members is specifically EXCLUDED from the definition of 'Immediate Family'?", choices: ["A Step-grandchildren", "B Guardian", "C Great-grandparents", "D Spouse's grandparents"], answer: 3, explanation: "Per Section 2.2 of Policy 3.04, a spouse's grandparents are explicitly NOT covered. Step-grandparents and great-grandparents are included, but a spouse's grandparents are excluded. This is the most common distractor in this policy." },
  { type: "multiple_choice", question: "Under Policy 3.04, bereavement leave must generally be taken within how many calendar days of the date of death?", choices: ["A 5 business days", "B 7 calendar days", "C 10 calendar days", "D 14 calendar days"], answer: 2, explanation: "Per Section 4.3 of Policy 3.04, bereavement leave must be taken within 10 calendar days immediately following the date of death." },
  { type: "multiple_choice", question: "Under Policy 3.04, if special funeral arrangements necessitate a delay, who may approve an exception to the standard 10-day window, and what is the absolute maximum extension?", choices: ["A The Captain may approve up to 30 calendar days", "B The Battalion Chief may approve up to 60 calendar days", "C The Department Director or designee may approve up to 90 calendar days from the date of death", "D The Director of Human Resources may approve up to 6 months from the date of death"], answer: 2, explanation: "Per Section 4.4 of Policy 3.04, the Department Director or designee may approve an exception for special arrangements, but this may not extend beyond 90 calendar days from the date of death." },
  { type: "multiple_choice", question: "Under Policy 3.04, in what increments must bereavement leave be taken?", choices: ["A Any increment of at least 1 hour", "B Half-day increments (minimum 4 hours)", "C Full-day increments only", "D The entire allotted balance must be taken at once"], answer: 2, explanation: "Per Policy 3.04, bereavement leave must be taken in full-day increments. Members cannot split shifts or use a few hours for a service and work the remainder of the day." },
  { type: "multiple_choice", question: "Under Policy 3.04, hours charged to bereavement leave have what effect on overtime computation?", choices: ["A They count as hours worked toward the overtime threshold", "B They are counted at double time toward the overtime threshold", "C They shall not be included toward hours worked for the computation of overtime pay", "D They count toward overtime only for 56-hour employees"], answer: 2, explanation: "Per Section 4.6 of Policy 3.04, hours charged to bereavement leave shall not be included toward the hours worked for the computation of overtime pay." },
  { type: "multiple_choice", question: "Under Policy 3.04, if a firefighter's parent and sibling die in the same month, how is the bereavement leave handled?", choices: ["A The two deaths are combined into one event with a doubled allotment", "B The employee must choose which death to use the bereavement leave for", "C Each death is treated as a separate event with a separate leave allotment", "D The department director must approve any bereavement leave in excess of 56 hours in a single month"], answer: 2, explanation: "Per Section 4.4 of Policy 3.04, in the event of multiple deaths in the immediate family, each death is treated separately, meaning the leave allotment resets for each individual death event." },
  { type: "multiple_choice", question: "Under Policy 3.04, which of the following is explicitly NOT a permitted use of bereavement leave?", choices: ["A Attending the funeral service of an immediate family member", "B Coordinating burial arrangements for an immediate family member", "C Saving the leave to use for the later reading of a will or probate", "D Taking consecutive days off immediately following the death"], answer: 2, explanation: "Per Section 4.4 of Policy 3.04, bereavement leave cannot be 'saved' for later use regarding the reading of wills, probate, or to extend a vacation." },
  { type: "multiple_choice", question: "Under Policy 3.05 (Holidays), how many designated City holidays are observed annually?", choices: ["A 9", "B 10", "C 11", "D 12"], answer: 2, explanation: "Per Section 4.1 of Policy 3.05, the City designates 11 official paid holidays observed annually, including New Year's Day, MLK Day, Memorial Day, Juneteenth, Independence Day, Labor Day, Veterans Day, Thanksgiving Day, the day after Thanksgiving, Christmas Eve, and Christmas Day." },
  { type: "multiple_choice", question: "Under Policy 3.05, how many flexible personal holidays does a full-time employee receive per calendar year?", choices: ["A 2", "B 3", "C 4", "D 5"], answer: 1, explanation: "Per Section 4.2.A.1 of Policy 3.05, full-time employees receive three (3) flexible personal holidays per calendar year." },
  { type: "multiple_choice", question: "Under Policy 3.05, a flexible personal holiday for a firefighter working a 24-hour shift schedule is accounted for as how many hours?", choices: ["A 8 hours", "B 11.2 hours", "C 12 hours", "D 24 hours"], answer: 3, explanation: "Per Section 4.2.A.3 of Policy 3.05, a flexible personal holiday for firefighters is a 24-hour block of time to account for their shift schedule." },
  { type: "multiple_choice", question: "Under Policy 3.05, what happens to unused flexible personal holidays at the end of the calendar year?", choices: ["A They carry over into the next calendar year", "B They are paid out at separation from employment", "C They are forfeited; there is no carryover and no payout", "D They are converted to annual leave"], answer: 2, explanation: "Per Sections 4.2.A.4 and 4.2.A.6 of Policy 3.05, flexible personal holidays are 'use it or lose it'; they do not roll over into the next year and there is no payout for unused flexible holidays upon separation." },
  { type: "multiple_choice", question: "Under Policy 3.05, if a City-designated holiday falls on a Saturday, on which day is it observed?", choices: ["A That Saturday (the actual holiday)", "B The preceding Friday", "C The following Monday", "D The preceding Thursday"], answer: 1, explanation: "Per Section 5.1 of Policy 3.05, if a holiday falls on a Saturday, it is observed on the preceding Friday." },
  { type: "multiple_choice", question: "Under Policy 3.05, what is the standard holiday pay entitlement for a firefighter working a 21-day work period?", choices: ["A 8 hours", "B 10 hours", "C 11.2 hours", "D 24 hours"], answer: 2, explanation: "Per Section 5.5.D of Policy 3.05, the holiday pay entitlement for a firefighter working a 21-day work period is 11.2 hours." },
  { type: "multiple_choice", question: "Under Policy 3.05, if an employee is on an approved leave without pay for 15 or more consecutive calendar days immediately before a City holiday, what is their holiday pay eligibility?", choices: ["A Full holiday pay is provided regardless of unpaid leave status", "B They are not eligible for holiday pay for that holiday", "C They receive half of their standard holiday pay", "D They may substitute a flexible personal holiday to receive pay"], answer: 1, explanation: "Per Section 5.4 of Policy 3.05, if a member is on approved leave without pay for 15 or more consecutive calendar days immediately before a City holiday, they are not eligible for compensation for that holiday." },
  { type: "multiple_choice", question: "Under Policy 3.05, when both Christmas Eve and Christmas Day fall on a weekend, the two observed holidays are always which days?", choices: ["A The Saturday and Sunday on which they actually fall", "B The Thursday and Friday before Christmas weekend", "C The preceding Friday and the following Monday", "D The Monday and Tuesday after Christmas weekend"], answer: 2, explanation: "Per Section 5.3 of Policy 3.05, regardless of how Christmas Eve and Christmas Day fall on a weekend, the observed holidays are always the Friday before and the Monday after the Christmas weekend." },
  { type: "multiple_choice", question: "Under Policy 3.05, part-time employees scheduled to work 4 hours on a City holiday receive how much holiday pay?", choices: ["A 0 hours; part-time employees are not eligible for holiday pay", "B 4 hours; they receive pay for the portion they would have normally worked", "C 8 hours; the standard full-time holiday allotment", "D 11.2 hours; the firefighter holiday pay rate"], answer: 1, explanation: "Per Section 4.3 of Policy 3.05, part-time employees receive paid time off only for the hours they would have normally been scheduled to work on that holiday. They are not eligible for flexible personal holidays." },
  { type: "multiple_choice", question: "Under Policy 3.07 (Injury Leave), what is the maximum amount of injury leave an employee may use within a 24-month period?", choices: ["A 6 consecutive months", "B 12 consecutive or non-consecutive months", "C 18 months total", "D 24 months total"], answer: 1, explanation: "Per Section 4.2.A of Policy 3.07, employees are limited to using a maximum of 12 months of injury leave (whether consecutive or non-consecutive) within any 24-month period." },
  { type: "multiple_choice", question: "Under Policy 3.07, what is the absolute 'hard cap' deadline after which an employee is no longer entitled to use injury leave?", choices: ["A 12 months from the date of injury", "B 18 months from the date of injury", "C 2 years from the date of the original injury or illness", "D 3 years from the date of the original injury or illness"], answer: 2, explanation: "Per Section 4.2.B of Policy 3.07, eligibility to use injury leave expires exactly two years from the original date of injury or illness." },
  { type: "multiple_choice", question: "Under Policy 3.07, the Injury Leave Supplement is calculated to ensure the injured employee receives what total income when combined with Workers' Compensation?", choices: ["A 100% of their gross pay (before taxes)", "B 100% of their normal net pay (take-home pay)", "C 80% of their base salary", "D 66.6% of their regular rate of pay"], answer: 1, explanation: "Per Sections 2.3 and 5.3 of Policy 3.07, the Injury Leave Supplement is calculated to ensure the employee receives their normal net pay (take-home pay), not gross pay, when combined with Workers' Compensation or VLDP benefits." },
  { type: "multiple_choice", question: "Under Policy 3.07, part-time employees injured on the job are eligible for which benefits?", choices: ["A Both Workers' Compensation and the Injury Leave Supplement", "B Workers' Compensation benefits only; they are not eligible for the Injury Leave Supplement", "C The Injury Leave Supplement only; Workers' Compensation is for full-time employees only", "D Neither Workers' Compensation nor the Injury Leave Supplement"], answer: 1, explanation: "Per Sections 3.1 and 3.2 of Policy 3.07, while part-time employees are eligible for standard Workers' Compensation benefits, they are explicitly ineligible to receive the Injury Leave Supplement." },
  { type: "multiple_choice", question: "Under Policy 3.07, an employee on 'No Duty' status is found to be working at a second job while on injury leave. What is the consequence?", choices: ["A A written warning is issued and the supplement is suspended for 30 days", "B The employee's pay is reduced to 50% of the supplement", "C The injury leave and supplement are immediately terminated", "D The employee is referred to EAP and placed on probation"], answer: 2, explanation: "Per Section 7.2.A.1 of Policy 3.07, performing work for any employer other than the City (including self-employment) while on injury leave is grounds for the immediate termination of injury leave and the supplement." },
  { type: "multiple_choice", question: "Under Policy 3.07, if an employee on 'Restricted Duty' status refuses a transitional employment assignment that has been approved by their treating physician, what happens?", choices: ["A The employee is given 30 days to reconsider before benefits are affected", "B The employee may refuse with no impact on benefits if the assignment is in a different department", "C The employee immediately loses entitlement to injury leave and the supplement", "D The employee may appeal to the Department Director for an exemption"], answer: 2, explanation: "Per Sections 4.5.A and 7.2.A.4 of Policy 3.07, if an employee refuses a transitional employment assignment when approved by the treating physician, they immediately lose entitlement to injury leave and the injury leave supplement." },
  { type: "multiple_choice", question: "Under Policy 3.07, if a Workers' Compensation claim is initially under investigation and not deemed compensable, what leave must the employee use? And what happens if the claim is later approved?", choices: ["A Annual leave must be used; it is not converted if the claim is later approved", "B Compensatory time must be used; it is later paid out if the claim is approved", "C Sick leave must be used; if the claim is later approved, those hours are credited back to the employee's balance", "D No leave is required; the employee remains on full pay during the investigation period"], answer: 2, explanation: "Per Section 5.2.D of Policy 3.07, if a claim is not immediately deemed compensable, the employee must use accrued sick leave. If the claim is later approved, the leave status is retroactively changed to injury leave, and the used sick leave hours are credited back." },
  { type: "multiple_choice", question: "Under Policy 3.07, medical appointments for a work-related injury that occur during regular work hours are classified as what?", choices: ["A Sick leave usage", "B Personal time usage", "C Assigned place of duty (hours worked)", "D Administrative leave"], answer: 2, explanation: "Per Section 4.5.B.1 of Policy 3.07, appointments for work-related injuries during work hours are officially classified as 'assigned place of duty' (hours worked)." },
  { type: "multiple_choice", question: "Under Policy 3.09 (Military Leave), what is the paid military leave entitlement for a firefighter per federal fiscal year?", choices: ["A 168 hours (21 working days)", "B 240 hours", "C 336 hours", "D 388 work hours"], answer: 3, explanation: "Per Section 4.1.B and C of Policy 3.09, firefighters are specifically entitled to paid military leave up to a total of 388 work hours per Federal Fiscal Year, compared to 21 working days (168 hours) for standard employees." },
  { type: "multiple_choice", question: "Under Policy 3.09, the federal fiscal year is defined as which period?", choices: ["A January 1 through December 31", "B July 1 through June 30", "C October 1 through September 30", "D April 1 through March 31"], answer: 2, explanation: "Per Policy 3.09, the Federal Fiscal Year is defined as October 1 through September 30 of each year." },
  { type: "multiple_choice", question: "Under Policy 3.09, a firefighter completes a 45-day military deployment. Within how many calendar days must they submit a written request for reemployment?", choices: ["A Immediately upon completion of service", "B 7 calendar days after completion of service", "C 14 calendar days after completion of service", "D 90 calendar days after completion of service"], answer: 2, explanation: "Per Section 9.1 of Policy 3.09, for service periods between 31 and 180 days, the employee must submit a written request for reemployment no later than 14 calendar days after completing service." },
  { type: "multiple_choice", question: "Under Policy 3.09, a firefighter returns from a 200-day military deployment and is reemployed. For how long are they protected from dismissal (except for cause)?", choices: ["A 90 days", "B 180 days", "C One year", "D Two years"], answer: 2, explanation: "Per Section 11.0.A of Policy 3.09, an employee reemployed after more than 180 days of military service cannot be dismissed (except for cause) within one year of reemployment." },
  { type: "multiple_choice", question: "Under Policy 3.09, a firefighter on military leave without pay will stop accruing annual and sick leave after being in that status for more than how many consecutive calendar days?", choices: ["A 7 consecutive calendar days", "B 14 consecutive calendar days", "C 21 consecutive calendar days", "D 30 consecutive calendar days"], answer: 1, explanation: "Per Section 6.5 of Policy 3.09, employees do not accrue annual, sick, or personal leave while in a military leave without pay status for more than 14 consecutive calendar days." },
  { type: "multiple_choice", question: "Under Policy 3.09, if an employee performs military service for 31 days or more, they may be required to pay up to what percentage of the full health plan premium to continue coverage?", choices: ["A 50% of the full premium", "B 75% of the full premium", "C 100% of the full premium", "D 102% of the full premium"], answer: 3, explanation: "Per Policy 3.09, employees performing military service for 31 days or more may be required to pay up to 102% of the full health plan premium to continue their health coverage." },
  { type: "multiple_choice", question: "Under Policy 3.09, a firefighter on a 1-30 day deployment returns home at 11 p.m. and has a shift starting at 7 a.m. the next morning. When must the employee report for work?", choices: ["A At 7 a.m. as scheduled, with no exception", "B After 8 hours of rest (7 a.m. + 8 hours = 3 p.m.), with paid military leave covering the overlap", "C After 24 hours of rest (11 p.m. + 24 hours)", "D Within 14 calendar days; they may submit a written request for reemployment"], answer: 1, explanation: "Per Section 4.4 of Policy 3.09, for 1-30 day deployments, the employee is entitled to an 8-hour rest period. If that rest period overlaps with a scheduled shift, the employee receives paid military leave for the duration of that overlap." },
  { type: "multiple_choice", question: "Under Policy 3.09, a firefighter who has exhausted their 388 hours of paid military leave may cover additional military service hours by using which specific benefit?", choices: ["A Forced use of sick leave", "B Flexible personal holidays in full workday increments", "C A 40-hour administrative leave bank set aside for military purposes", "D Automatic conversion of accrued overtime to military leave"], answer: 1, explanation: "Per Section 4.6 of Policy 3.09, sworn firefighters may use flexible personal holidays in full workday increments to cover military absences once the initial 388-hour paid leave allotment is exhausted." },
  { type: "multiple_choice", question: "Under Policy 3.09, how is a 'working day' specifically defined for a firefighter for the purpose of calculating military leave entitlement?", choices: ["A A flat 24-hour period regardless of shift length", "B 8 hours, consistent with the standard federal workday", "C 1/260 of total scheduled work hours in a federal fiscal year", "D 1/168 of the monthly scheduled hours"], answer: 2, explanation: "Per Section 2.11.B of Policy 3.09, a 'working day' for a firefighter is calculated as 1/260 of their total scheduled work hours in a federal fiscal year." },
  { type: "multiple_choice", question: "Under Policy 3.10 (Sick Leave), at what rate do firefighters on a 56-hour workweek accrue sick leave per month?", choices: ["A 8 hours per month", "B 9.6 hours per month", "C 11.2 hours per month", "D 14 hours per month"], answer: 2, explanation: "Per Section 4.1 of Policy 3.10, firefighters assigned to a 56-hour workweek accrue sick leave at a rate of 11.2 hours per month." },
  { type: "multiple_choice", question: "Under Policy 3.10, a 56-hour firefighter has been absent 58 consecutive working hours. Is a written medical statement mandatory, and if so, who must it be submitted to?", choices: ["A No; the threshold for mandatory documentation is 80 consecutive hours for firefighters", "B Yes; written medical authorization is mandatory and must be submitted to the immediate supervisor", "C Yes; mandatory once the absence exceeds 56 consecutive working hours, and must be submitted to Occupational Health Services (OHS)", "D Yes; mandatory after any absence exceeding 40 hours, and must be submitted to HR/ER"], answer: 2, explanation: "Per Section 4.2.D.2 of Policy 3.10, written medical authorization is mandatory after an absence exceeding 56 consecutive working hours for firefighters, and per policy, it must be submitted to Occupational Health Services (OHS)." },
  { type: "multiple_choice", question: "Under Policy 3.10, a medical statement required after a sick leave absence must contain which of the following as a mandatory component?", choices: ["A A list of all medications prescribed during the absence", "B The anticipated date of medical release with specific limitations and the expected date of return to normal duties", "C The name of the employee's insurance provider", "D A statement from the employee's direct supervisor supporting the leave request"], answer: 1, explanation: "Per Section 4.2.D.2 of Policy 3.10, required doctor's statements must include: (1) the nature of the condition, (2) the anticipated date of medical release with specific limitations, and (3) the expected date the employee can perform normal work duties." },
  { type: "multiple_choice", question: "Under Policy 3.10, what is the annual cap on using personal sick leave to care for family members (Family Sick Leave) for a 56-hour firefighter?", choices: ["A 40 hours per calendar year", "B 56 hours per calendar year", "C 80 hours per calendar year", "D There is no cap; the full sick leave bank may be used for family members"], answer: 1, explanation: "Per Section 4.3 of Policy 3.10, the use of sick leave for family members is capped at 56 hours per calendar year for 56-hour firefighters." },
  { type: "multiple_choice", question: "Under Policy 3.10, accrued sick leave is paid out at what rate upon a qualifying event (such as retirement)?", choices: ["A At the employee's regular hourly rate with no cap", "B At a rate of $28.00 per 8 hours", "C At a rate of $50.00 per 8 hours", "D At 50% of the employee's regular hourly rate"], answer: 1, explanation: "Per Section 4.7 of Policy 3.10, accrued sick leave is paid out at a rate of $28.00 per eight (8) hours upon a qualifying event." },
  { type: "multiple_choice", question: "Under Policy 3.10, a firefighter with 1,120 hours of accrued sick leave is retiring. What is the correct payout calculation?", choices: ["A (1,120 / 8) x $28", "B (1,120 / 11.2) x $28", "C (1,120 / 56) x $28", "D (1,120 x $28) / 40"], answer: 1, explanation: "Per Section 4.7.B.1 of Policy 3.10, to calculate a line firefighter's payout, the total balance is divided by 11.2 and then multiplied by the $28 rate. Therefore the formula is (1,120 / 11.2) x $28." },
  { type: "multiple_choice", question: "Under Policy 3.10, in what specific increments may a firefighter on a 56-hour schedule take sick leave?", choices: ["A In any increment of at least 0.25 hours", "B In increments of 0.8 or 0.6 hours, and only when combined with Birthday Leave or a Personal Flexible Holiday", "C In full 24-hour increments only", "D In 1-hour increments, provided it is for a medical appointment"], answer: 1, explanation: "Per Section 4.2.A.2 of Policy 3.10, firefighters on the line may only take sick leave in increments of 0.8 and 0.6 hours, and only if combined with Birthday Leave or a Personal Flexible Holiday." },
  { type: "multiple_choice", question: "Under Policy 3.10, which of the following is included in the definition of 'Immediate Family Member' for Family Sick Leave purposes?", choices: ["A Aunt or Uncle", "B First Cousin", "C Great-grandparent", "D Brother-in-law"], answer: 2, explanation: "Per Section 2.3 of Policy 3.10, the family member definition includes great-grandparents. Aunts, uncles, cousins, and brothers-in-law are not included in the definition." },
  { type: "multiple_choice", question: "Under Policy 3.10, a supervisor (as the department director's designee) may require a doctor's statement under what circumstances?", choices: ["A Only after the employee exceeds the mandatory documentation threshold (40 or 56 consecutive hours)", "B Only when abuse is suspected for absences exceeding the family sick leave cap", "C At any time, regardless of the amount of sick leave taken", "D Only after three or more separate sick leave occurrences in a calendar year"], answer: 2, explanation: "Per Section 4.2.D.1 of Policy 3.10, the Department Director or designee may require a doctor's statement at any time regardless of the amount of sick leave taken." },
  { type: "multiple_choice", question: "Under Policy 3.15 (Maternity and Parental Leave), how many hours of paid maternity leave is a firefighter on a 56-hour workweek granted?", choices: ["A 240 hours (6 weeks)", "B 280 hours", "C 336 hours (6 weeks)", "D 480 hours"], answer: 2, explanation: "Per Section 5.1.A of Policy 3.15, firefighters who work a 56-hour workweek shall be granted six (6) weeks of paid maternity leave, which equals 336 hours." },
  { type: "multiple_choice", question: "Under Policy 3.15, paid maternity leave for a birthing mother must be used in what format?", choices: ["A Consecutively or intermittently at the employee's preference", "B Intermittently, to allow for gradual return to full duty", "C Consecutively only; it cannot be used intermittently", "D Consecutively, but only for a minimum of 3 weeks at a time"], answer: 2, explanation: "Per Section 5.4 of Policy 3.15, paid maternity leave for a birthing mother must be consecutive and cannot be used intermittently." },
  { type: "multiple_choice", question: "Under Policy 3.15, a non-birthing parent's paid parental bonding leave must be utilized within what timeframe following the birth or adoption?", choices: ["A Within 6 weeks following birth or adoption", "B Within 12 weeks following birth or adoption", "C Within 6 months following birth or adoption", "D Within 12 months following birth or adoption"], answer: 1, explanation: "Per Section 6.1.A.2 and 6.1.B.3 of Policy 3.15, paid parental leave must be utilized within 12 weeks following the birth or adoption of a child." },
  { type: "multiple_choice", question: "Under Policy 3.15, a firefighter's spouse gives birth to twins. How does this affect the amount of paid parental leave the non-birthing firefighter receives?", choices: ["A The leave is doubled because there are two children", "B The leave is increased by 50% for each additional child beyond the first", "C Multiple births during one event do not impact the amount of paid parental leave granted", "D The firefighter must request additional leave through an exception process approved by the Department Director"], answer: 2, explanation: "Per Section 6.1.A.3 of Policy 3.15, multiple births during one event do not impact the amount of paid parental leave granted." },
  { type: "multiple_choice", question: "Under Policy 3.15, which of the following individuals is explicitly EXCLUDED from paid maternity or parental leave?", choices: ["A Non-birthing parents for adoption", "B Foster parents placing a child into foster care", "C An employee in loco parentis caring for a child", "D A non-birthing parent for a newborn birth"], answer: 1, explanation: "Per Section 6.1.B.5 of Policy 3.15, placing a child into foster care is explicitly not eligible for paid parental leave. Additionally, per Section 5.7, surrogate mothers are not eligible for paid maternity leave." },
  { type: "multiple_choice", question: "Under Policy 3.15, how much paid parental leave is available to an employee caring for a sick parent with a serious health condition?", choices: ["A Six (6) weeks within a 12-month period", "B Four (4) weeks within a 12-month period", "C Two (2) weeks within a 12-month period", "D One (1) week within a 12-month period"], answer: 3, explanation: "Per Section 6.2.A of Policy 3.15, eligible employees receive exactly one (1) week of paid parental leave within a 12-month period to care for a sick parent with a serious health condition." },
  { type: "multiple_choice", question: "Under Policy 3.15, if a newborn child dies during the period of paid maternity leave, how is the leave handling changed?", choices: ["A The maternity leave is extended by an additional 2 weeks", "B The remaining maternity leave is converted to annual leave", "C The employee must transition to the City's Bereavement Leave Policy (3.04) in lieu of paid maternity leave", "D The maternity leave continues unchanged; no adjustment is required"], answer: 2, explanation: "Per Section 5.8 of Policy 3.15, in the event that a newborn child dies during the period of paid maternity leave, the City's Bereavement Leave Policy (#3.04) shall be used in lieu of paid maternity leave." },
  { type: "multiple_choice", question: "Under Policy 3.15, paid maternity and parental leave is based on which component of the employee's compensation?", choices: ["A Base salary including all overtime and standby pay", "B Base salary only, excluding overtime or standby pay", "C The average total compensation over the preceding 12 months", "D The employee's gross pay including shift differentials"], answer: 1, explanation: "Per Section 5.2 and 6.1.A.1 of Policy 3.15, paid maternity and parental leave is based on the employee's base salary, not including overtime or standby pay." },
  { type: "multiple_choice", question: "Under Policy 3.15, a neonatal care exception allowing delayed utilization of paid parental leave may be approved by the Department Director, but this exception cannot extend beyond when?", choices: ["A 12 weeks following the birth or adoption placement", "B 3 months following the birth", "C 6 months following the birth of the child", "D 12 months following the birth of the child"], answer: 2, explanation: "Per Section 6.1.A.6 and 6.1.B.6 of Policy 3.15, the Department Director or designee may approve delayed utilization for neonatal care, but exception approvals may not extend beyond six (6) months following the birth of the child." },
  { type: "multiple_choice", question: "Under Policy 3.15, how many times may an employee utilize paid maternity or parental leave benefits within a 12-month period?", choices: ["A One time only per 12-month period", "B No more than two times in a 12-month period", "C Three times if each event involves a different child", "D There is no stated limit if FML is approved each time"], answer: 1, explanation: "Per Sections 5.1 and 6.1 of Policy 3.15, an employee can receive paid maternity leave or paid parental leave no more than two (2) times in a 12-month period." },
  { type: "multiple_choice", question: "Under Policy 3.17 (Administrative Leave), what is the definition of 'Regularly Scheduled Hours' for a part-time employee who may be eligible for administrative leave?", choices: ["A Any part-time employee working at least 20 hours per week", "B An employee who has worked for the City for at least one year in a part-time capacity", "C A part-time employee scheduled for the same number of hours per week, every week, for at least 90 days preceding the need for leave", "D A part-time employee averaging at least 32 hours per week over the preceding 6 months"], answer: 2, explanation: "Per Section 2.2 of Policy 3.17, 'regularly scheduled hours' means a part-time employee is scheduled for the same number of hours per week, every week, for at least ninety (90) days preceding the need for Administrative Leave." },
  { type: "multiple_choice", question: "Under Policy 3.17, when a member tests positive on an evidentiary alcohol breath test, what is the correct minimum administrative leave duration?", choices: ["A Exactly 24 hours, regardless of shift schedule", "B Until the start of the next regularly scheduled workday, or 24 hours, whichever is later", "C Up to 72 hours pending further investigation", "D Three consecutive scheduled workdays"], answer: 1, explanation: "Per Section 5.1.A of Policy 3.17, a positive alcohol test results in administrative leave until the start of the next regularly scheduled workday, or twenty-four (24) hours, whichever is later." },
  { type: "multiple_choice", question: "Under Policy 3.17, when reasonable suspicion of drug use exists, how long may the initial administrative leave last while awaiting laboratory results?", choices: ["A 24 hours maximum", "B Until the next scheduled workday", "C Up to 72 hours", "D Up to 5 business days"], answer: 2, explanation: "Per Section 5.1.B of Policy 3.17, a member placed on administrative leave for reasonable suspicion of drug use may be held on that status for up to seventy-two (72) hours pending laboratory results." },
  { type: "multiple_choice", question: "Under Policy 3.17, when a member tests positive for alcohol and returns to work after administrative leave, what must the Captain do?", choices: ["A Issue a written reprimand before the member returns to duty", "B Escort the member to OSHS to confirm their fitness for duty", "C Notify the union representative prior to the member's return", "D Have the member complete an EAP referral form before starting their shift"], answer: 1, explanation: "Per Section 5.1.C.2 of Policy 3.17, upon the member's return to work after a positive alcohol test, the supervisor must escort them to OSHS to confirm their fitness for duty." },
  { type: "multiple_choice", question: "Under Policy 3.17, administrative leave during a workplace misconduct investigation is the exception, not the rule. A Department Director may place an employee on administrative leave for up to how many consecutive workdays without HR director approval?", choices: ["A 1 consecutive workday", "B 3 consecutive workdays", "C 5 consecutive workdays", "D 7 consecutive workdays"], answer: 1, explanation: "Per Section 5.2.A of Policy 3.17, a department director can place an employee on administrative leave for up to three (3) consecutive workdays during a misconduct investigation, subject to specific conditions being met." },
  { type: "multiple_choice", question: "Under Policy 3.17, who must provide written approval to extend administrative leave beyond the initial period during a misconduct investigation?", choices: ["A The Fire Chief", "B The City Manager", "C The Director of Human Resources, or designee", "D The Senior City Attorney"], answer: 2, explanation: "Per Section 5.2.B of Policy 3.17, any extension of administrative leave beyond the initial three-day period requires written approval from the Director of Human Resources, or designee." },
  { type: "multiple_choice", question: "Under Policy 3.17, when an employee is notified of a pre-disciplinary meeting where termination is being considered, when does the administrative leave begin?", choices: ["A At the discretion of the Department Director", "B Immediately following the confirmed delivery of the pre-disciplinary meeting notice", "C After the conclusion of the pre-disciplinary meeting itself", "D Two calendar days before the effective date of termination"], answer: 1, explanation: "Per Section 5.3.A of Policy 3.17, administrative leave begins immediately following the confirmed delivery of a pre-disciplinary meeting notice where termination is being considered. This is mandatory, not discretionary." },
  { type: "multiple_choice", question: "Under Policy 3.17, for an officer-involved incident involving use of deadly force, on which day does the three-day administrative leave period begin?", choices: ["A The day of the event itself", "B The day after the event", "C Two days after the event", "D The next regularly scheduled workday following the event"], answer: 1, explanation: "Per Section 5.4.A of Policy 3.17, for officer-involved incidents involving use of deadly force or in-custody death, the three (3) day administrative leave period commences the day after the event." },
  { type: "multiple_choice", question: "Under Policy 4.02 (Discipline), which of the following is NOT defined as a formal disciplinary action?", choices: ["A Written Reprimand", "B Suspension", "C Verbal coaching and counseling session", "D Demotion"], answer: 2, explanation: "Per Policy 4.02, the City considers verbal warnings, coaching, and counselings to be performance management tools and not forms of formal discipline. The formal disciplinary actions are: Written Reprimand, Suspension, Demotion, and Dismissal." },
  { type: "multiple_choice", question: "Under Policy 4.02, before imposing any discipline, a supervisor must first take what action?", choices: ["A Contact Human Resources to draft a disciplinary letter", "B Place the employee on administrative leave pending investigation", "C Conduct a fact-finding investigation", "D Issue a verbal warning"], answer: 2, explanation: "Per Policy 4.02, before imposing any discipline, a supervisor shall first conduct a fact-finding (investigation) process." },
  { type: "multiple_choice", question: "Under Policy 4.02, during a standard fact-finding meeting with a department supervisor, is the employee entitled to have a personal representative present?", choices: ["A Yes, they may have any representative of their choice", "B Yes, but only a union representative or attorney", "C No, employees are not entitled to have a personal representative during the fact-finding process", "D Yes, but the representative may observe only and may not speak"], answer: 2, explanation: "Per Policy 4.02, employees are not entitled to have a personal representative at any meeting with a department supervisor during the fact-finding process." },
  { type: "multiple_choice", question: "Under Policy 4.02, when a firefighter is subject to an interrogation that could lead to punitive action, the interrogation must take place at which location?", choices: ["A The Office of the City Attorney", "B The Firefighter's assigned station", "C The facility where the investigating officer is assigned", "D A neutral, mutually agreed upon location"], answer: 2, explanation: "Per Policy 4.02 (incorporating Virginia Code 9.1-300), the interrogation shall take place at the facility where the investigating officer is assigned." },
  { type: "multiple_choice", question: "Under Policy 4.02, when a pre-disciplinary meeting involves a proposed suspension of 40 or more hours, how much advance written notice must the employee receive?", choices: ["A 12 hours", "B 24 hours", "C 48 hours", "D 5 business days"], answer: 1, explanation: "Per Policy 4.02, when termination, demotion, or a suspension of 40 or more hours is considered, departments shall provide a minimum of 24 hours written notice of the pre-disciplinary meeting." },
  { type: "multiple_choice", question: "Under Policy 4.02, all formal disciplinary letters must contain which mandatory element?", choices: ["A A list of all prior disciplinary actions received by the employee", "B The signatures of both the supervisor and the HR Director", "C A warning that future unsatisfactory performance or misconduct may result in further disciplinary action", "D Approval from the City Manager"], answer: 2, explanation: "Per Policy 4.02, all documents imposing discipline shall contain a warning that future unsatisfactory performance or misconduct may result in further disciplinary action." },
  { type: "multiple_choice", question: "Under Policy 4.02, what is the minimum retention period before a Written Reprimand may be requested to be purged from the official personnel file?", choices: ["A 12 months", "B 18 months", "C 2 years", "D 3 years"], answer: 1, explanation: "Per Policy 4.02, the minimum retention period for a letter of reprimand is eighteen (18) months before it can be requested to be purged." },
  { type: "multiple_choice", question: "Under Policy 4.02, a Suspension shall no longer be considered as a prior disciplinary factor (for penalty enhancement purposes) after how many years, provided no further discipline occurred?", choices: ["A 2 years", "B 3 years", "C 5 years", "D 7 years"], answer: 2, explanation: "Per Policy 4.02, a suspension shall not be considered after five (5) years, provided no further disciplinary action was imposed within the intervening five (5) years." },
  { type: "multiple_choice", question: "Under Policy 4.02, an employee is found to have knowingly and intentionally misused City funds through improper Procurement Card use. What is the prescribed penalty?", choices: ["A A suspension of 40 hours and restitution", "B A demotion and written reprimand", "C Restitution and a written reprimand only", "D Dismissal"], answer: 3, explanation: "Per Policy 4.02, employees found to have knowingly and with intent misused City funds shall be dismissed." },
  { type: "multiple_choice", question: "Under Policy 4.02, job abandonment may be determined after an employee fails to report to work without explanation for how many consecutive workdays?", choices: ["A 2 consecutive workdays", "B 3 consecutive workdays", "C 5 consecutive workdays", "D 1 pay period"], answer: 1, explanation: "Per Policy 4.02, job abandonment is determined if an employee fails to report to work for three (3) consecutive workdays or more without explanation." },
  { type: "multiple_choice", question: "Under Policy 4.02, an employee previously dismissed for a founded allegation of violating the Workplace Violence Prevention Policy (6.17) applies for reemployment with the City. What does the policy dictate?", choices: ["A They may be re-employed after a minimum waiting period of 1 year", "B They may be employed through a temporary services contract immediately", "C They shall not be re-employed by the City", "D They must undergo a psychological evaluation before consideration for re-employment"], answer: 2, explanation: "Per Policy 4.02, no individual shall be re-employed when dismissed for a founded allegation of the Workplace Violence Prevention Policy." },
  { type: "multiple_choice", question: "Under Policy 4.02, a sworn law enforcement officer (or other employee) found to be untruthful after a fact-finding investigation shall receive what penalty?", choices: ["A A suspension of 80 hours", "B A demotion to the lowest rank", "C Placement on a Last Chance Agreement", "D Dismissal"], answer: 3, explanation: "Per Policy 4.02, sworn law enforcement officers (and by general expectation, employees found to be untruthful) found to be untruthful after a fact-finding investigation shall be dismissed." },
  { type: "multiple_choice", question: "Under Policy 4.02, 'mitigating factors' such as length of service are considered when selecting a penalty EXCEPT in which circumstance?", choices: ["A When the employee is a supervisor or officer", "B When dismissal is mandated under other City policies, laws, or regulations", "C When the employee has prior written reprimands on record", "D When the offense involves performance rather than misconduct"], answer: 1, explanation: "Per Policy 4.02, mitigating factors are not considered when dismissal is mandated under other City policies, laws, or regulations." },
  { type: "multiple_choice", question: "Under Policy 4.04 (Grievance), a Type A Grievance is defined as pertaining to which of the following?", choices: ["A Any discrimination complaint regardless of severity", "B Any performance evaluation dispute", "C Dismissal, demotion, or suspension for more than 40 consecutive working hours", "D Any application of policy that is misinterpreted by management"], answer: 2, explanation: "Per Policy 4.04, a Type A Grievance pertains to the most severe disciplinary actions: dismissal, demotion, or suspension for more than forty (40) consecutive working hours." },
  { type: "multiple_choice", question: "Under Policy 4.04, which of the following is explicitly defined as a NON-grievable complaint (management right)?", choices: ["A Discrimination on the basis of race or national origin", "B Acts of retaliation for participating in the grievance process", "C The failure to promote an employee where promotional policies were not followed", "D The establishment and revision of wages and position classifications"], answer: 3, explanation: "Per Section 4.1 of Policy 4.04, the establishment and revision of wages, salaries, position classifications, or general benefits is explicitly listed as a non-grievable management right." },
  { type: "multiple_choice", question: "Under Policy 4.04, a grievance must be initiated within how many consecutive calendar days of the occurrence or the employee's knowledge of the occurrence?", choices: ["A 10 consecutive calendar days", "B 15 consecutive calendar days", "C 20 consecutive calendar days", "D 30 consecutive calendar days"], answer: 2, explanation: "Per Policy 4.04, the initial grievance filing at Step 1 must occur within 20 consecutive calendar days of the occurrence or the employee's knowledge of the occurrence." },
  { type: "multiple_choice", question: "Under Policy 4.04, a Type A grievant's primary option is to appeal directly to the Personnel Board. How many consecutive calendar days does the employee have to provide written notice of their intent to do so?", choices: ["A 10 consecutive calendar days of the action", "B 15 consecutive calendar days of the action", "C 20 consecutive calendar days of the action", "D 30 consecutive calendar days of the action"], answer: 2, explanation: "Per Section 6.1 of Policy 4.04, for a Type A direct appeal to the Personnel Board, the grievant must provide written notice within twenty (20) consecutive calendar days of the grievable action." },
  { type: "multiple_choice", question: "Under Policy 4.04, a supervisor has how many consecutive calendar days to provide a verbal reply to a Step 1 grievance discussion?", choices: ["A 5 consecutive calendar days", "B 10 consecutive calendar days", "C 15 consecutive calendar days", "D 20 consecutive calendar days"], answer: 1, explanation: "Per Policy 4.04's Master Timeline, the supervisor's verbal reply at Step 1 must be provided within 10 consecutive calendar days of the grievance discussion." },
  { type: "multiple_choice", question: "Under Policy 4.04, who issues a binding decision on a grievability determination request?", choices: ["A The Department Director", "B The Personnel Board", "C The City Manager or the Director of Human Resources", "D The Virginia Beach Circuit Court"], answer: 2, explanation: "Per Section 4.2 of Policy 4.04, the City Manager or the Director of Human Resources will issue a binding decision on a grievability determination within ten (10) consecutive calendar days of receiving the request." },
  { type: "multiple_choice", question: "Under Policy 4.04, at which steps in the Type B grievance process may an employee be represented by an individual of their choice, including legal counsel?", choices: ["A At all four steps", "B Only at Step 4 (Personnel Board)", "C At Steps 3 and 4", "D At Steps 2, 3, and 4"], answer: 2, explanation: "Per Section 7.0 of Policy 4.04, at Steps 3 and 4, an employee may be represented by an individual of their choice, including legal counsel, at their own expense." },
  { type: "multiple_choice", question: "Under Policy 4.04, regarding mediation within the grievance process, which of the following is TRUE?", choices: ["A Mediation is mandatory before a grievance can proceed to Step 4", "B Mediation is voluntary and requires the consent of both parties", "C If mediation is unsuccessful, the grievance is dismissed entirely", "D Only management may initiate a request for mediation"], answer: 1, explanation: "Per Section 7.0 of Policy 4.04, mediation is a voluntary process that requires the consent of both parties. If mediation is unsuccessful, the grievance returns to the step it was at before mediation began." },
  { type: "multiple_choice", question: "Under Policy 4.04, temporary, probationary, or seasonal employees are eligible to use the grievance procedure up to and including which step, and for what types of actions?", choices: ["A Steps 1 and 2 only, for all grievable actions", "B Steps 1 through 3 only, and not for dismissal", "C All four steps, but not for disciplinary actions", "D No steps; they are entirely ineligible for the grievance procedure"], answer: 1, explanation: "Per Policy 4.04, temporary, probationary, or seasonal employees have limited eligibility and can only use the grievance procedure up to and including Step Three, and not for dismissal." },
  { type: "multiple_choice", question: "Under Policy 4.04, 'consecutive calendar days' as used for all timelines in the policy includes which of the following?", choices: ["A Only regular workdays, excluding weekends and holidays", "B Only days on which city offices are open for business", "C All calendar days, including weekends, holidays, and all forms of leave", "D All calendar days except the days the employee is on approved leave"], answer: 2, explanation: "Per Policy 4.04, 'consecutive calendar days' includes all days on the calendar: normal workdays, weekend days, holidays, and all forms of leave." },
  { type: "multiple_choice", question: "Under Policy 6.13 (Workplace Harassment), harassment is prohibited based on which of the following lists of protected classes?", choices: ["A Race, color, sex, religion, and national origin only (the Title VII classes)", "B Race, color, sex, religion, national origin, disability, age, pregnancy, genetics, military status, sexual orientation, and gender identity", "C Race, color, sex, religion, and disability only", "D All of the above, plus political affiliation and marital status"], answer: 1, explanation: "Per Section 3.1 of Policy 6.13, the City prohibits harassment on the basis of 12 specific protected classes: race, color, sex, religion, national origin, disability, age, pregnancy or childbirth, genetics, military status, sexual orientation, and gender identity." },
  { type: "multiple_choice", question: "Under Policy 6.13, which of the following persons is protected by this policy's applicability provisions?", choices: ["A Only full-time City employees", "B Only full-time City employees and sworn officers", "C All employees, applicants, temporary contract workers, and volunteers", "D All employees and contractors, but not applicants or volunteers"], answer: 2, explanation: "Per Section 2.1 of Policy 6.13, the policy applies to all part-time and full-time employees, all applicants in consideration for employment, all temporary contract workers, and all volunteers providing services to the City." },
  { type: "multiple_choice", question: "Under Policy 6.13, 'leering' is classified under which category of prohibited conduct?", choices: ["A Verbal conduct", "B Visual conduct", "C Physical conduct", "D Retaliatory conduct"], answer: 2, explanation: "Per Section 4.2.C of Policy 6.13, leering, stares, and lewd hand gestures are classified as physical conduct." },
  { type: "multiple_choice", question: "Under Policy 6.13, dating is specifically prohibited between which individuals?", choices: ["A Any two employees in the same department", "B Any two employees within the same Fire Station or precinct", "C Supervisors and any employee in their chain of command in the same division, workgroup, or work unit", "D Any supervisor and any other City employee, regardless of department"], answer: 2, explanation: "Per Section 4.4.D of Policy 6.13, dating is strictly prohibited between supervisory personnel and employees in the supervisor's chain of command within the same division, workgroup, or work unit." },
  { type: "multiple_choice", question: "Under Policy 6.13, if a volunteer is found to be in violation of the harassment policy, what is the consequence?", choices: ["A They are subject to discipline under Policy 4.02 just like an employee", "B They are immediately removed from their assignment", "C They are prohibited from working for the City under the contract", "D They are referred to EAP for mandatory counseling"], answer: 1, explanation: "Per Section 3.6 of Policy 6.13, any volunteers found in violation of this policy shall be removed from their assignment with the City of Virginia Beach." },
  { type: "multiple_choice", question: "Under Policy 6.13, which section specifically prohibits discrimination or harassment against an individual because of their marriage or familial relationship to a person who filed a harassment complaint?", choices: ["A Section 3.1 (general prohibition on discrimination)", "B Section 3.3.A (extended prohibitions)", "C Section 4.4.D (dating prohibition)", "D Section 6.2.B (adverse action prohibition)"], answer: 1, explanation: "Per Section 3.3.A of Policy 6.13, the City also prohibits discrimination or harassment against an individual because of their marriage to or other familial relationship to an individual who has lodged a complaint of discrimination or harassment." },
  { type: "multiple_choice", question: "Under Policy 6.13, 'Quid Pro Quo' sexual harassment occurs when submission to conduct is what type of condition of employment?", choices: ["A Only an explicit (written or clearly stated) term or condition", "B Only an implicit (implied) term or condition", "C Either an explicit or an implicit term or condition of employment", "D Only when the conduct is perpetrated by a supervisor"], answer: 2, explanation: "Per Section 4.4.A.1 of Policy 6.13, sexual harassment includes situations where submission to the conduct is either an explicit or implicit term or condition of employment." },
  { type: "multiple_choice", question: "Under Policy 6.13, retaliation for filing a harassment complaint may include which of the following adverse employment actions?", choices: ["A Failure to hire or promote only", "B Disciplinary actions only", "C Termination only", "D All of the above: failure to hire, failure to promote, disciplinary actions, and termination"], answer: 3, explanation: "Per Section 6.2.A of Policy 6.13, no employee or applicant shall be subject to retaliation that may include any adverse employment act such as failure to hire or promote, disciplinary actions, or termination." },
  { type: "multiple_choice", question: "Under Policy 6.13, complaint investigation procedures are governed by which separate City policy?", choices: ["A Policy 4.02 (Discipline Policy)", "B Policy 4.04 (Grievance Policy)", "C Policy 6.06 (Equal Employment Opportunity Policy and Complaint Procedure)", "D Policy 6.17 (Workplace Violence Prevention Policy)"], answer: 2, explanation: "Per Section 5.0 of Policy 6.13, procedures and responsibilities for reporting complaints refer to Policy 6.06 (Equal Employment Opportunity Policy and Complaint Procedure)." },
  { type: "multiple_choice", question: "Under Policy 6.17 (Workplace Violence), what is the definition of 'Assault' under this policy?", choices: ["A An offensive touching or use of force without consent", "B A completed or attempted attack with a weapon resulting in serious injury", "C An act, gesture, or words intended to threaten or scare another, conveying a sense of imminent threat (no physical contact required)", "D Any verbal conduct that causes emotional distress"], answer: 2, explanation: "Per Section 2.2 of Policy 6.17, assault is when an individual intends to threaten or scare another into believing they are going to be physically harmed. The act, gesture, or words must convey a sense of imminent threat. Physical contact is not required." },
  { type: "multiple_choice", question: "Under Policy 6.17, a pocketknife is classified as a 'weapon' if the blade length exceeds what measurement?", choices: ["A 2 inches", "B 2.5 inches", "C 3 inches", "D 4 inches"], answer: 2, explanation: "Per Section 2.14 of Policy 6.17, pocketknives with blades longer than three (3) inches are considered weapons. Any snap-blade or spring-blade knife is prohibited regardless of blade length." },
  { type: "multiple_choice", question: "Under Policy 6.17, a firefighter makes a threat toward a coworker but says 'I was just joking.' How does the policy treat this threat?", choices: ["A It is not a policy violation if the person clearly meant it as a joke", "B It is a minor infraction warranting verbal counseling only", "C The threat is treated as serious regardless of whether the person claims to be joking, kidding, or not serious", "D It is only a policy violation if the coworker perceived it as a genuine threat"], answer: 2, explanation: "Per Section 5.1 of Policy 6.17, any threat or act of violence will be treated as though the instigator was serious even if the person indicates he/she is joking, kidding, or wasn't serious." },
  { type: "multiple_choice", question: "Under Policy 6.17, who chairs the Threat Assessment Team?", choices: ["A The Police Chief or designee", "B The Department Director of the affected department", "C The HR/Employee Relations Manager or designee", "D The Director of Occupational Safety and Health Services (OSHS)"], answer: 2, explanation: "Per Section 8.1 of Policy 6.17, the Threat Assessment Team is chaired by the Human Resources-Employee Relations Manager or designee." },
  { type: "multiple_choice", question: "Under Policy 6.17, which department was specifically added to the Threat Assessment Team in the October 18, 2021 revision?", choices: ["A Occupational Safety and Health Services (OSHS)", "B City Attorney's Office", "C Office of Emergency Management (OEM)", "D Police Department"], answer: 2, explanation: "Per the Revision History in Section 15.0 of Policy 6.17, the October 18, 2021 revision specifically added the Office of Emergency Management to the Threat Assessment Team." },
  { type: "multiple_choice", question: "Under Policy 6.17, what is the phone number for HR/Employee Relations that should be used to report a workplace violence violation?", choices: ["A 1-800-869-8522", "B 757-385-3170", "C 757-385-8949", "D 911"], answer: 2, explanation: "Per Section 7.1 of Policy 6.17, reports can be made by contacting Human Resources - Employee Relations (HR/ER) at 757-385-8949." },
  { type: "multiple_choice", question: "Under Policy 6.17, what does the acronym R.E.S.P.E.C.T. stand for?", choices: ["A Reporting Every Situation Promptly Ensures Collective Trust", "B Report Employee Situations Promptly to Enable Change Together", "C Respond Effectively to Situations to Protect Employees from Conflict and Threats", "D Reporting Employees Suspected of Preventing Effective Civil Treatment"], answer: 1, explanation: "Per Section 2.8 of Policy 6.17, R.E.S.P.E.C.T. stands for Report Employee Situations Promptly to Enable Change Together." },
  { type: "multiple_choice", question: "Under Policy 6.17, an employee who violates the policy and receives discipline OTHER than termination shall receive what mandatory consequence?", choices: ["A A mandatory last-chance agreement", "B A mandatory transfer to a different work assignment", "C A mandatory referral to the Employee Assistance Program (EAP)", "D A mandatory demotion of at least one grade"], answer: 2, explanation: "Per Sections 11.2 and 12.2 of Policy 6.17, any employee who violates this policy and receives discipline other than termination shall receive a mandatory referral to the Employee Assistance Program (EAP)." },
  { type: "multiple_choice", question: "Under Policy 6.17, if an employee who receives a mandatory EAP referral fails to attend EAP sessions or fails to follow the EAP representative's recommendations, what may happen?", choices: ["A Their EAP referral is simply extended for an additional period", "B They receive a written reprimand added to their file", "C They are subject to disciplinary action, up to and including dismissal", "D They are placed on unpaid administrative leave for 30 days"], answer: 2, explanation: "Per Section 11.3 of Policy 6.17, if an employee who receives a mandatory referral to EAP fails to attend an EAP session or to follow the recommendations of the EAP representative, the employee will be subject to disciplinary action, up to and including dismissal." },
  { type: "multiple_choice", question: "Under Policy 6.17, which of the following is defined as part of the 'Workplace' for the purposes of this policy?", choices: ["A Only the interior of the primary work building", "B Only City-owned property and City-owned vehicles", "C The building, surrounding perimeters, parking lots, alternate work locations, travel to and from work assignments, and City-owned or leased vehicles", "D Only locations where the employee performs their primary assigned duties"], answer: 2, explanation: "Per Section 2.15 of Policy 6.17, the 'Workplace' includes any location where an employee performs work-related duty, including buildings, surrounding perimeters, parking lots, alternate work locations, travel to and from work assignments, and City-owned or leased vehicles." },
  { type: "multiple_choice", question: "Under Policy 6.17, if an employee obtains a Personal Protective Order (PPO) against another individual they might encounter at work, what is the employee required to do?", choices: ["A Nothing; a PPO is a personal legal matter and need not be disclosed to the employer", "B Advise their supervisor of the existence of the protective order", "C Immediately request a transfer to a different work location", "D Contact the HR/ER department directly, bypassing the supervisor"], answer: 1, explanation: "Per Section 7.7 of Policy 6.17, employees who have obtained a protective order from a court against another employee, contract worker, volunteer, or other individual they may encounter during employment are required to advise their supervisor of the existence of the protective order." },
  { type: "multiple_choice", question: "Under Policy 6.17, the City's right to search City Property (lockers, desks, computers, vehicles) is described as what type of right?", choices: ["A A right requiring a court-issued search warrant", "B A conditional right requiring employee consent", "C An absolute right with zero employee expectation of privacy", "D A right that may be exercised only during formal investigations approved by HR"], answer: 2, explanation: "Per Section 9.2 of Policy 6.17, the City reserves the absolute right to search City Property including offices, computers, computer files, computer drives, city vehicles, file cabinets, desks, and lockers for the purpose of ensuring compliance with this policy." },
  { type: "multiple_choice", question: "Under Policy 6.17, 'Battery' is defined as which of the following?", choices: ["A Intent to threaten or scare without physical contact", "B A completed or attempted attack with a weapon causing serious injury", "C An offensive touching or use of force on a person without consent, which must make the victim fear imminent physical harm", "D Any verbal or written conduct causing emotional distress"], answer: 2, explanation: "Per Section 2.4 of Policy 6.17, Battery is an offensive touching or use of force on a person without the person's consent. The touching does not have to cause injury but must make the victim fear imminent physical harm." }
];

// Merge into main QUESTION_BANK
if (typeof QUESTION_BANK !== 'undefined') {
  if (!QUESTION_BANK["HR Policies"]) QUESTION_BANK["HR Policies"] = [];
  QUESTION_BANK["HR Policies"].push(...HR_POLICIES_QUESTIONS);
}
